-- STEG 3: import av saknade inskrifter ur rundata.sql (landskap Hs, 22 rader).
-- 22 kandidatrader. id = rundatas objectid (UUID) => spegeltabeller matchar.
-- Dedup: WHERE NOT EXISTS på signum + ON CONFLICT(id). Ren data, idempotent. Kör i editorn.
insert into public.runic_inscriptions
  (id, signum, alternative_signum, coordinates, coord_source, coord_confidence,
   transliteration, normalization, translation_sv, translation_en, dating_text,
   scholarly_notes, object_type, material, landscape, country, data_source)
select
  v.id::uuid, v.signum,
  case when v.alt is not null then string_to_array(v.alt,'|') else null::text[] end,
  case when v.lat is not null then point(v.lng::float8, v.lat::float8) else null::point end,
  case when v.lat is not null then 'rundata_evighetsrunor' else null end,
  case when v.lat is not null then 'high' else null end,
  v.translit, v.norm, v.tsv, v.ten, v.dating, v.notes, v.otype, v.material, v.landscape,
  coalesce(v.country,'Sweden'), 'rundata_evighetsrunor'
from (values
('52291c91-eca5-4a66-8cd8-15efcd6b2092','Hs 2','L 1061',61.3604,16.9867,': anasuiþr : auk utrikr auk sikbiurn '' þiʀ litu rita stin ×¶× aftiʀ katilbiurn : auk anunt : sun hans : auk saufaraʀ ¶ kuþ hialbi [:] a-- ------------------ --rki þita','"<anasuiþr> ok "Otryggʀ ok "Sigbiorn, þæiʀ letu retta stæin æftiʀ "Kætilbiorn ok "Anund, sun hans, ok "Søyvaraʀ(?). "Guð hialpi a[nd] … [mæ]rki þetta.',NULL,'<anasuiþr> and Ótryggr and Sigbjǫrn, they had the stone erected in memory of Ketilbjǫrn and his and Seyvǫr''s(?) son Ǫnundr. May God help (their) spirits … this landmark.',NULL,NULL,'Runsten','Sandsten','Hälsingland','Sweden'),
('3c76dc3d-def4-431e-937e-fc0d2c15ddb6','Hs 12','L 1069',61.7664,17.0402,'kuþniutr ⁓ þru sun ⁓ lit rita stin þina ⁓ ak bru kirþi ⁓ aftiʀ bruþr sina ⁓ asbiurn : ak at kuþlaf','"Guðnjótr "Þóru(?) sonr lét rétta stein þenna ok brú gerði eptir brœðr sína, "Ásbjǫrn ok at "Guðlaf.',NULL,'Guðnjótr Þóru(?)''s son had this stone erected and made the bridge in memory of his brothers Ásbjǫrn and in memory of Guðlafr.',NULL,NULL,'Runsten','Sten','Hälsingland','Sweden'),
('9c45d7ec-e24d-4c6f-8532-234ab1c735f7','Hs 21','L 1071',61.9741,17.2589,'asmuntr · ok fa[r]þ[i]k[l] · þiʀ ritu stin · þina · aftiʀ þu[rkatil · faþur sin · a utrunkum · k]unburka faþ[i stin þina in kuþa]','"Ásmundr ok "Farþegn, þeir réttu stein þenna eptir "Þorketil, fǫður sinn, á "Vatrungum. "Gunnborga fáði stein þenna, hin góða.',NULL,'Ásmundr and Farþegn, they erected this stone in memory of Þorketill of Vattrång, their father. Gunnborga the good coloured this stone.',NULL,NULL,'Runsten','Sedimentgnejs','Hälsingland','Sweden'),
('721c0a03-4163-49bb-b0d0-4bf06b28a804','Hs 3',NULL,61.3609,16.9859,'…-i','…',NULL,'…',NULL,'Eventuellt kan fragmentet höra ihop med Hs 4.','Fragment av runsten','Röd sandsten','Hälsingland','Sweden'),
('e6c73cbf-6c90-4454-8cf2-fc0725f6ca91','Hs 17','L 1070',61.8136,16.5691,'[…i : stin þinsa| |aftiʀ bruþr : sin… … …un :]','… stein þenna eptir brœðr sín[a] … …',NULL,'… this stone in memory of his brothers …',NULL,NULL,'Runsten','Sten','Hälsingland','Sweden'),
('69be7dd9-e4d2-4370-a017-4f487e7d03aa','Hs 7','L 1952',61.7342,16.9391,'§A ⁓ uksa tuiskilan auk aura tuo staf at fursta laki ⁓ uksa tuo auk aura fiura| |at aþru laki ⁓ ¶ ⁓ in at þriþia laki uksa fiura| |auk aura| |ata staf ⁓ auk alt aiku i uarʀ if an hafsk aki rit furiʀ §B ⁓ suaþ liuþiʀ aku at liuþriti sua uas int fur auk halkat ⁓ in þaʀ kirþu sik þita| |anunr o tarstaþum ⁓ ¶ ⁓ auk ufakʀ o hiurtstaþum ⁓ in uibiurn faþi ⁓ §B ⁓ suaþ liuþiʀ aku at liuþriti sua uas int fur auk halkat ⁓ in þaʀ kirþu sikþ| |þita| |anunr o tarstaþum ⁓ ¶ ⁓ auk ufakʀ o hiurtstaþum ⁓ in uibiurn faþi ⁓','§A Oxa tvisgildan ok aura tvá staf at fyrsta lagi, oxa tvá ok aura fjóra at ǫðru lagi, en at þriðja lagi oxa fjóra ok aura átta staf, ok allt eigu í verr, ef hann hafsk ekki rétt fyrir, §B svát ljóðir eigu at ljóðrétti, svá var innt fyrr ok helgat. En þeir gerðu sik(?) þetta, "Ǫnundr á "Társtǫðum ok "Ófeigr á "Hjǫrtstǫðum. En "Vébjǫrn fáði. §B svát ljóðir eigu at ljóðrétti, svá var innt fyrr ok helgat. En þeir gerðu segð(?) þétta(?), "Ǫnundr á "Társtǫðum ok "Ófeigr á "Hjǫrtstǫðum. En "Vébjǫrn fáði.',NULL,'§A One ox and two ounces of silver (in fine) to the staff for the restoration of a sanctuary in a valid state for the first time; two oxen and four ounces of silver (in fine) for the second time; but for the third time four oxen and eight ounces of silver (in fine); and all property in suspension, if he doesn''t make right. §B That, the people are entitled to demand, according to the law of the people, that was decreed and ratified before. But they made themselves this "ring", Anund from Tåsta and Ofeg from Hjortsta. But Vibjörn painted. §B That, the people are entitled to demand, according to the law of the people, that was decreed and ratified before. But they made the pronouncement(?) tight(?), Anund from Tåsta and Ofeg from Hjortsta. But Vibjörn painted.','800-talet','En kopia finns i sakristian.','Ring','Järn','Hälsingland','Sweden'),
('fa40d544-ccee-4642-86c6-7782037b8ba2','Hs 14','L 1065',61.8091,17.2004,'§A hrumuntr| |rit… staina þina| |aftiʀ hikiulf- ⁓ brisa sun (⁓) in brisi uas lina sun : in lini uas unaʀ sun : in un ua… …faks| |sun i(n) (u)fak a þuris| |sun ¶ hrumunt hikiulfa sun faþi runaʀ þisaʀ : uiʀ sutum stin þina nur i balas…in : ¶ krua uas muþiʀ hikiulf… ¶ in þa barlaf in þa kuþrun ⁓ §B kiulfiʀ uarþ um lanti þisu in þa nur i uika þrim bium in þa lanakri| |in þa fiþrasiu','§A "Hróðmundr rétt[i] stein/steina þenna/þessa eptir "Hé-Gylf[a] "Brísa son. En "Brísi var "Lina sonr. En "Lini var "Unar sonr. En "Unn va[r "Ó]feigs sonr. En "Ófeig[r v]a[r] "Þóris sonr. "Hróðmundr, "Hé-Gylfa sonr, fáði rúnar þessar. Vér sóttum stein þenna norðr í "Balas[te]in. "Gróa var móðir "Hé-Gylf[a]/"Hé-Gylf[is]. En þá "Berglǫf/"Bergleif. En þá "Guðrún. §B "Gylfir varð um landi þessu, en þá norðr í vega/"<uika> þrím býjum, en þá "Lønangri, en þá "Feðrasjó.',NULL,'§A Hróðmundr erected this/these stone/s in memory of Hé-Gylfir, Brísi''s son. And Brísi was Lini''s son. And Lini was Unn''s son. And Unn was Ófeigr''s son. And Ófeigr was Þórir''s son. Hróðmundr, Hé-Gylfir''s son, coloured these runes. We sought this stone in the north in Balasteinn. Gróa was Hé-Gylfir''s mother. And then Berglǫf/Bergleif. And then Guðrún. §B Gylfir acquired this land and then three estates in a northerly direction / <uika> in the north, and then Lønangr and then Feðrasjór.',NULL,'En kopia står på den ursprungliga platsen.','Runsten','Sten','Hälsingland','Sweden'),
('d9305727-f631-48a1-917c-a50eda570485','Hs 18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Utgör en del av Hs 16',NULL,NULL,'Hälsingland','Sweden'),
('2ef21d28-700f-490c-a868-d2b8cf21469e','Hs ATA322-2795-2011',NULL,61.7663,17.0409,'§A fu §B fuþ §C fuþo §D fuþor §E fuþork','§A <fu[þork]> §B <fuþ[ork]> §C <fuþo[rk]> §D <fuþor[k]> §E <fuþork>',NULL,'§A <fuþork> §B <fuþork> §C <fuþork> §D <fuþork> §E <fuþork>','1190-talet','Runorna finns på takstolarna 6-10.','Inskrifter på takstolar','Trä','Hälsingland','Sweden'),
