('8f0d637a-a71c-478c-a968-ea10f2a15ec3','Hs 16','L 1683',61.8192,16.5609,'§A … …untr : krib(i)[s| |sun : risti : -…] …ruþur hanaʀ (i)[auaʀiu : aikil… …aþi : … …(r)kaþi stin ¶ þin…] §B […(k)uin…]','§A … "…undr, "Gripis sunn, ræisti … [b]roður hennaʀ … … … … [ma]rkaði stæin þenn[a]. §B …',NULL,'§A … -undr, Grípir''s son, raised … her brother. … marked this stone. §B …',NULL,NULL,'Runsten','Granit','Hälsingland','Sweden'),
('f3732511-11ff-4c93-be56-443bb4542477','Hs 10','L 1067',61.754,17.0806,'[…-…l]f runaʀ sun lina (s)tin þina f…(þ)… sum sunan i na… fur ¶ …a…i(þ)bnu + a…t… st[in þina] aftiʀ sunu sina þria hruþmar in þ(o)…flt '' uma(h)l ¶ … ¶ in brusi asbiarnaʀ sun fa[þ]… : runaʀ þi… ¶ … raþa ·','… rúnar, sonr "Lina, stein þenna … sem sunnan í … … … … stein þenna eptir sonu sína þrjá "Hróðmar en … … … En "Brúsi "Ásbjarnar sonr fáð[i] rúnar þe[ssar]. … ráða(?).',NULL,'… the runes / Álfrúnar(?), Lini''s son, this stone … who in the south … this stone in memory of his three sons, Hróðmarr and … And Brúsi Ásbjǫrn''s son coloured these runes. … interpret(?).',NULL,NULL,'Runsten','Granatådergnejs','Hälsingland','Sweden'),
('a5663757-ff19-43c8-a6d8-e3067879b662','Hs 8','L 1063',61.7263,17.105,'[⁓ bariʀþ ⁓ riti stain ⁓ þina ⁓ aftiʀ un ⁓ … bruþur sin ⁓ han uas| |sun ⁓ arinbiarnaʀ a-þuaun-ua-sun ⁓ ialni su- ant unaʀ]','"<bariʀþ> rétti stein þenna eptir "Un … bróður sinn. Hann var sonr "Arinbjarnar. … Hjalpi "Gu[ð] ǫnd "Unar.',NULL,'<bariʀþ> erected this stone in memory of Unn his brother. He was Arinbjǫrn''s son … May God help Unn''s spirit.',NULL,NULL,'Runsten','Sten','Hälsingland','Sweden'),
('85932206-7ed8-4894-ba5a-eeb2548cb669','Hs 4',NULL,61.338,17.0371,NULL,NULL,NULL,NULL,NULL,'Endast ornamentala linjer finns på det lilla fragmentet. Eventuellt kan det höra ihop med Hs 3.','Fragment av runsten','Röd sandsten','Hälsingland','Sweden'),
('54bd79ce-c676-4cad-83bf-d446bd265c84','Hs 15','L 1064',61.8081,17.2471,'hrumuntr hikiulfis| |sun riti stain þina| |aftiʀ hikiu-(f)a bris(a) sun : hrumun- in þa þurmunt in þa snrariʀ i- þa un','"Hroðmundr "He-Gylfis sunn retti stæin þenna æftiʀ "He-Gy[l]fa "Brisa sun. "Hroðmun[dr], en þa "Þormundr, en þa "Snærriʀ, e[n] þa "Unn.',NULL,'Hróðmundr, Hé-Gylfir''s son, erected this stone in memory of Hé-Gylfir, Brísi''s son. Hróðmundr, and then Þormundr, and then Snerrir, and then Unn.',NULL,NULL,'Runsten','Granit','Hälsingland','Sweden'),
('f8a98089-081f-4587-b183-f0e6cb59b1b6','Hs 6','L 1062',61.7098,16.1814,': unulfr : auk fiuluar : ristu stin þinsa : iftiʀ : tiuʀo : faþur sin : hriþulfs| |sun : auk at : haurlau : muþur sina : fiuluars tutur : o uitkuþ:staþum :','"Unnulfʀ ok "Fiolvarr ræistu stæin þennsa æftiʀ "Diuʀa, faður sinn, "Hræiðulfs sun, ok at "Haurlaug(?), moður sina, "Fiolvars dottur a "Viðkunnsstaðum.',NULL,'Unnulfr and Fjǫlvarr raised this stone in memory of Djúri, their father, Hreiðulfr''s son, and in memory of Haurlaug(?), their mother, Fjǫlvarr of Viðkunnsstaðir''s daughter.',NULL,NULL,'Runsten','Granit','Hälsingland','Sweden')
) as v(id, signum, alt, lat, lng, translit, norm, tsv, ten, dating, notes, otype, material, landscape, country)
where not exists (
  select 1 from public.runic_inscriptions ri
  where lower(regexp_replace(ri.signum,'\s+',' ','g')) = lower(regexp_replace(v.signum,'\s+',' ','g'))
)
on conflict (id) do nothing;
